mapper.update:
UPDATE tb_inspection_template
SET
    active = #{active},
    updated_at = NOW(6)
WHERE company_id = #{companyId}
  AND template_id = #{templateId}

UPDATE tb_inspection_template
SET updated_at = NOW(6)
WHERE template_id = #{templateId}

UPDATE tb_inspection_template_item
SET active = #{active}
WHERE template_id = #{templateId}
  AND item_id = #{itemId}

UPDATE tb_inspection_template_item
SET sort_order = CASE item_id

    WHEN #{sortOrder.id} THEN #{sortOrder.sortOrder}

END
WHERE template_id = #{templateId}
  AND item_group = #{itemGroup}
  AND item_id IN

    #{sortOrder.id}

UPDATE tb_inspection_template_item_option
SET active = FALSE
WHERE item_id = #{itemId}

UPDATE tb_inspection_template_item_option
SET
    option_label = #{optionLabel},
    option_value = #{optionValue},
    sort_order = #{sortOrder},
    active = #{active}
WHERE item_id = #{itemId}
  AND option_id = #{optionId}

UPDATE tb_inspection_template_item_option
SET active = #{active}
WHERE item_id = #{itemId}
  AND option_id = #{optionId}

UPDATE tb_inspection_template_item_option
SET sort_order = CASE option_id

    WHEN #{sortOrder.id} THEN #{sortOrder.sortOrder}

END
